-- Seed: 90 curiosities + 10 house ads (Aside as initial sponsor).
-- English. Generated from scripts/curiosities.en.json. Inserts only when empty.

do $$
declare
  aside uuid;
begin
  if (select count(*) from curiosities) > 0 then
    return;
  end if;

    values (aside, now() - interval '1 day', now() + interval '365 days', 'live');

end $$;
